// Generated by Copilot
import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import {
  Enums,
  RenderingEngine,
  type Types,
} from '@cornerstonejs/core';
import * as dicomImageLoader from '@cornerstonejs/dicom-image-loader';
import {
  Enums as csToolsEnums,
  LengthTool,
  PanTool,
  ToolGroupManager,
  WindowLevelTool,
  ZoomTool,
} from '@cornerstonejs/tools';
import { cn } from '../../lib/utils';
import { buildDicomPreviewDataUrl, type DicomPreviewResult } from '../../utils/dicomPreview';
import { DicomWorkspaceView, FileData, DicomMetadata, ThemeMode } from '../../types';
import { ensureCornerstoneReady } from '../../utils/cornerstone';
import { parseDicomInfo } from '../../utils/dicomMetadata';
import { useToast } from '../ui/use-toast';
import { TlantiOhifActionMenu } from './DicomViewerActionMenu';
import { TlantiOhifClinicalDock } from './DicomViewerClinicalDock';
import { TlantiOhifErrorIndicator, TlantiOhifLoadingIndicator } from './DicomViewerIndicators';
import { TlantiOhifToolbar, TlantiOhifTool } from './DicomViewerToolbar';
import { TlantiOhifRenderMode } from './DicomViewerRenderStatus';
import { TlantiOhifStudyPanel } from './DicomViewerStudyPanel';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from '@/components/ui/sheet';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Activity, Box, Download, FileText, Layers3, Move3d, ScanSearch, Sparkles } from 'lucide-react';
import { getTlantiCadToolsForFile } from '@/lib/tlanticad-tools-registry';

interface TlantiOhifViewerProps {
  file: FileData;
  onUpdate: (id: string, updates: Partial<FileData>) => void;
  onMetadataLoaded?: (id: string, metadata: DicomMetadata) => void;
  themeMode: ThemeMode;
}

interface DentalVolumePreviewPayload {
  study?: {
    patientName?: string | null;
    modality?: string | null;
    studyDate?: string | null;
    seriesDescription?: string | null;
    dimensions?: string | null;
    sliceCount?: number | null;
    previewPngBase64?: string | null;
  };
  volume?: {
    sliceCount?: number | null;
    volumeShape?: number[] | null;
    spacingZyxMm?: number[] | null;
    huRange?: number[] | null;
    reconstructionMode?: string | null;
  };
  previews?: {
    axialMipPngBase64?: string | null;
    coronalMipPngBase64?: string | null;
    sagittalMipPngBase64?: string | null;
    panoramicPngBase64?: string | null;
    archOverlayPngBase64?: string | null;
  };
}

const toolMap: Record<TlantiOhifTool, string> = {
  windowLevel: WindowLevelTool.toolName,
  pan: PanTool.toolName,
  zoom: ZoomTool.toolName,
  length: LengthTool.toolName,
};

function parseDimensions(dimensions?: string | null) {
  const [width, height] = (dimensions ?? '0x0').split('x').map((value) => Number.parseInt(value, 10) || 0);
  return { width, height };
}

export function TlantiOhifViewer({
  file,
  onUpdate,
  onMetadataLoaded,
  themeMode,
}: TlantiOhifViewerProps) {
  const { toast } = useToast();
  const viewportRef = useRef<HTMLDivElement | null>(null);
  const renderingEngineRef = useRef<RenderingEngine | null>(null);
  const toolGroupId = useMemo(() => `tlanti-ohif-toolgroup-${file.id}`, [file.id]);
  const renderingEngineId = useMemo(() => `tlanti-ohif-engine-${file.id}`, [file.id]);
  const viewportId = useMemo(() => `tlanti-ohif-viewport-${file.id}`, [file.id]);
  const imageIdsRef = useRef<string[]>([]);

  const [activeTool, setActiveTool] = useState<TlantiOhifTool>('windowLevel');
  const [isInverted, setIsInverted] = useState(false);
  const [isReady, setIsReady] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [metadata, setMetadata] = useState<DicomMetadata | undefined>(file.dicomMetadata);
  const [fallbackPreview, setFallbackPreview] = useState<DicomPreviewResult | null>(null);
  const [useFallbackPreview, setUseFallbackPreview] = useState(false);
  const [volumePreview, setVolumePreview] = useState<DentalVolumePreviewPayload | null>(null);
  const [isVolumeLoading, setIsVolumeLoading] = useState(false);
  const [volumeError, setVolumeError] = useState<string | null>(null);
  const [isInspectorOpen, setIsInspectorOpen] = useState(true);
  const [isDockCollapsed, setIsDockCollapsed] = useState(false);
  const [isDetailsSheetOpen, setIsDetailsSheetOpen] = useState(false);

  const workspaceView = (file.dicomWorkspaceView ?? 'review') as DicomWorkspaceView;

  const totalSlices = file.buffers?.length || 1;
  const currentBuffer = useMemo(() => {
    if (file.buffers?.length) {
      const safeIndex = Math.min(Math.max(file.sliceIndex || 0, 0), file.buffers.length - 1);
      return file.buffers[safeIndex] ?? null;
    }

    return file.buffer ?? null;
  }, [file.buffer, file.buffers, file.sliceIndex]);

  useEffect(() => {
    if (!currentBuffer) {
      setFallbackPreview(null);
      return;
    }

    const nextPreview = buildDicomPreviewDataUrl(currentBuffer, {
      adjustments: file.dicomAdjustments,
      invert: isInverted,
      windowCenter: file.windowCenter,
      windowWidth: file.windowWidth,
    });

    setFallbackPreview(nextPreview);
  }, [currentBuffer, file.dicomAdjustments, file.windowCenter, file.windowWidth, isInverted]);

  useEffect(() => {
    const buffers = file.buffers?.length ? file.buffers : file.buffer ? [file.buffer] : [];
    if (!buffers.length) {
      setVolumePreview(null);
      setVolumeError(null);
      return;
    }

    let cancelled = false;
    const controller = new AbortController();

    const loadRemotePreview = async () => {
      setIsVolumeLoading(true);
      setVolumeError(null);

      try {
        const formData = new FormData();
        buffers.forEach((buffer, index) => {
          formData.append('files', new File([buffer], `${file.name.replace(/\s+/g, '_')}_${index + 1}.dcm`, { type: 'application/dicom' }));
        });

        const response = await fetch('http://127.0.0.1:17493/dicom/volume-preview', {
          method: 'POST',
          body: formData,
          signal: controller.signal,
        });

        if (!response.ok) {
          throw new Error(`FastAPI volume preview returned ${response.status}`);
        }

        const payload = await response.json() as DentalVolumePreviewPayload;
        if (cancelled) {
          return;
        }

        setVolumePreview(payload);

        const previewBase64 = payload.study?.previewPngBase64;
        if (previewBase64) {
          const { width, height } = parseDimensions(payload.study?.dimensions);
          setFallbackPreview((current) => current ?? {
            dataUrl: `data:image/png;base64,${previewBase64}`,
            width,
            height,
            source: 'backend',
          });
        }

        const mergedMetadata: DicomMetadata = {
          ...file.dicomMetadata,
          patientName: payload.study?.patientName ?? file.dicomMetadata?.patientName,
          modality: payload.study?.modality ?? file.dicomMetadata?.modality,
          studyDate: payload.study?.studyDate ?? file.dicomMetadata?.studyDate,
          seriesDescription: payload.study?.seriesDescription ?? file.dicomMetadata?.seriesDescription,
          dimensions: payload.study?.dimensions ?? file.dicomMetadata?.dimensions,
          sliceCount: payload.study?.sliceCount ?? file.dicomMetadata?.sliceCount ?? 0,
        };
        setMetadata(mergedMetadata);
        onMetadataLoaded?.(file.id, mergedMetadata);
      } catch (remoteError) {
        if (cancelled || controller.signal.aborted) {
          return;
        }

        setVolumeError(
          remoteError instanceof Error
            ? remoteError.message
            : 'No se pudo generar la vista de volumen desde FastAPI.',
        );
      } finally {
        if (!cancelled) {
          setIsVolumeLoading(false);
        }
      }
    };

    void loadRemotePreview();

    return () => {
      cancelled = true;
      controller.abort();
    };
  }, [file.buffer, file.buffers, file.dicomMetadata, file.id, file.name, onMetadataLoaded]);

  useEffect(() => {
    if (isReady) {
      setUseFallbackPreview(false);
      return;
    }

    if (!fallbackPreview) {
      return;
    }

    const timeoutId = window.setTimeout(() => {
      setUseFallbackPreview(true);
    }, 1400);

    return () => window.clearTimeout(timeoutId);
  }, [fallbackPreview, isReady]);

  useEffect(() => {
    if (error && fallbackPreview) {
      setUseFallbackPreview(true);
    }
  }, [error, fallbackPreview]);

  useEffect(() => {
    if (isReady || error) {
      return;
    }

    const timeoutId = window.setTimeout(() => {
      if (fallbackPreview) {
        setUseFallbackPreview(true);
        return;
      }

      setError(totalSlices > 1
        ? 'No se pudo completar el render del stack DICOM. Importa la carpeta completa o el ZIP del estudio para detectar la serie completa.'
        : 'No se pudo completar el render DICOM. Si este archivo pertenece a una serie, importa la carpeta completa o selecciona el ZIP del estudio.');
    }, 4500);

    return () => window.clearTimeout(timeoutId);
  }, [error, fallbackPreview, isReady, totalSlices]);

  const applyToolMode = useCallback(() => {
    const toolGroup = ToolGroupManager.getToolGroup(toolGroupId);
    if (!toolGroup) {
      return;
    }

    Object.values(toolMap).forEach((toolName) => {
      toolGroup.setToolPassive(toolName);
    });

    toolGroup.setToolActive(toolMap[activeTool], {
      bindings: [{ mouseButton: csToolsEnums.MouseBindings.Primary }],
    });
  }, [activeTool, toolGroupId]);

  const applyViewportState = useCallback(async () => {
    const renderingEngine = renderingEngineRef.current;
    if (!renderingEngine || !isReady) {
      return;
    }

    const viewport = renderingEngine.getViewport(viewportId) as Types.IStackViewport | undefined;
    if (!viewport) {
      return;
    }

    const targetIndex = Math.min(Math.max(file.sliceIndex || 0, 0), imageIdsRef.current.length - 1);
    if (targetIndex >= 0 && imageIdsRef.current.length > 0) {
      await (viewport as any).setImageIdIndex(targetIndex);
    }

    viewport.setProperties({
      voiRange: {
        lower: file.windowCenter - file.windowWidth / 2,
        upper: file.windowCenter + file.windowWidth / 2,
      },
      invert: isInverted,
    });

    viewport.render();
  }, [file.sliceIndex, file.windowCenter, file.windowWidth, isInverted, isReady, viewportId]);

  const resetViewport = useCallback(() => {
    const renderingEngine = renderingEngineRef.current;
    const viewport = renderingEngine?.getViewport(viewportId) as Types.IStackViewport | undefined;
    if (!viewport) {
      return;
    }

    viewport.resetCamera();
    viewport.setProperties({
      voiRange: {
        lower: file.windowCenter - file.windowWidth / 2,
        upper: file.windowCenter + file.windowWidth / 2,
      },
      invert: isInverted,
    });
    viewport.render();
  }, [file.windowCenter, file.windowWidth, isInverted, viewportId]);

  useEffect(() => {
    let cancelled = false;

    const setup = async () => {
      const element = viewportRef.current;
      if (!element) {
        return;
      }

      setError(null);
      setIsReady(false);

      try {
        await ensureCornerstoneReady();
        if (cancelled) {
          return;
        }

        const buffers = file.buffers?.length ? file.buffers : file.buffer ? [file.buffer] : [];
        if (!buffers.length) {
          throw new Error('El archivo DICOM no contiene buffers utilizables.');
        }

        const parsedInfo = parseDicomInfo(buffers[0], buffers.length);
        if (parsedInfo) {
          const mergedMetadata: DicomMetadata = {
            ...parsedInfo.metadata,
            ...file.dicomMetadata,
            warnings: file.dicomMetadata?.warnings ?? parsedInfo.metadata.warnings,
            missingSlices: file.dicomMetadata?.missingSlices ?? parsedInfo.metadata.missingSlices,
            originalSliceCount: file.dicomMetadata?.originalSliceCount ?? parsedInfo.metadata.originalSliceCount,
            subsampleStep: file.dicomMetadata?.subsampleStep ?? parsedInfo.metadata.subsampleStep,
          };
          setMetadata(mergedMetadata);
          onMetadataLoaded?.(file.id, mergedMetadata);

          const updates: Partial<FileData> = {};
          if (
            parsedInfo.windowCenter !== undefined &&
            parsedInfo.windowWidth !== undefined &&
            file.windowCenter === 40 &&
            file.windowWidth === 400
          ) {
            updates.windowCenter = parsedInfo.windowCenter;
            updates.windowWidth = parsedInfo.windowWidth;
          }

          if (Object.keys(updates).length > 0) {
            onUpdate(file.id, updates);
          }
        }

        const blobs = buffers.map(
          (buffer, index) =>
            new File([buffer], `${file.name.replace(/\s+/g, '_')}_${index + 1}.dcm`, {
              type: 'application/dicom',
            }),
        );

        imageIdsRef.current = blobs.map((blob) => dicomImageLoader.wadouri.fileManager.add(blob));

        const renderingEngine = new RenderingEngine(renderingEngineId);
        renderingEngineRef.current = renderingEngine;

        element.oncontextmenu = (event) => event.preventDefault();
        renderingEngine.enableElement({
          viewportId,
          element,
          type: Enums.ViewportType.STACK,
        });

        const viewport = renderingEngine.getViewport(viewportId) as Types.IStackViewport;

        let toolGroup = ToolGroupManager.getToolGroup(toolGroupId);
        if (!toolGroup) {
          toolGroup = ToolGroupManager.createToolGroup(toolGroupId);
        }

        if (!toolGroup) {
          throw new Error('No se pudo crear el grupo de herramientas del viewer.');
        }

        setUseFallbackPreview(false);
        Object.values(toolMap).forEach((toolName) => toolGroup!.addTool(toolName));
        toolGroup.addViewport(viewportId, renderingEngineId);

        await viewport.setStack(
          imageIdsRef.current,
          Math.min(Math.max(file.sliceIndex || 0, 0), imageIdsRef.current.length - 1),
        );
        viewport.setProperties({
          voiRange: {
            lower: file.windowCenter - file.windowWidth / 2,
            upper: file.windowCenter + file.windowWidth / 2,
          },
          invert: false,
        });
        viewport.render();

        if (!cancelled) {
          setIsReady(true);
        }
      } catch (viewerError) {
        console.error(viewerError);
        if (!cancelled) {
          setError(
            viewerError instanceof Error
              ? viewerError.message
              : 'La inicialización del viewer falló de forma inesperada.',
          );
        }
      }
    };

    setup();

    return () => {
      cancelled = true;
      ToolGroupManager.destroyToolGroup(toolGroupId);
      renderingEngineRef.current?.destroy();
      renderingEngineRef.current = null;
      imageIdsRef.current = [];
    };
  }, [
    file.id,
    file.buffer,
    file.buffers,
    file.name,
    onMetadataLoaded,
    onUpdate,
    renderingEngineId,
    toolGroupId,
    viewportId,
  ]);

  useEffect(() => {
    if (isReady) {
      applyToolMode();
    }
  }, [applyToolMode, isReady]);

  useEffect(() => {
    applyViewportState();
  }, [applyViewportState]);

  const handleWheel = useCallback(
    (event: React.WheelEvent<HTMLDivElement>) => {
      if (totalSlices <= 1) {
        return;
      }

      event.preventDefault();
      event.stopPropagation();

      const delta = event.deltaY > 0 ? 1 : -1;
      const nextIndex = Math.min(Math.max((file.sliceIndex || 0) + delta, 0), totalSlices - 1);
      if (nextIndex !== file.sliceIndex) {
        onUpdate(file.id, { sliceIndex: nextIndex });
      }
    },
    [file.id, file.sliceIndex, onUpdate, totalSlices],
  );

  const dicomAdjustments = file.dicomAdjustments ?? {
    rotation: 0,
    crop: { top: 0, right: 0, bottom: 0, left: 0 },
  };

  const renderMode = useMemo<TlantiOhifRenderMode>(() => {
    if (error && !useFallbackPreview) {
      return 'error';
    }

    if (isReady && !useFallbackPreview) {
      return 'cornerstone';
    }

    if (useFallbackPreview && fallbackPreview?.source === 'backend') {
      return 'backend-preview';
    }

    if (useFallbackPreview && fallbackPreview) {
      return 'local-preview';
    }

    return 'loading';
  }, [error, fallbackPreview, isReady, useFallbackPreview]);

  const cropStyle = {
    clipPath: `inset(${dicomAdjustments.crop.top}% ${dicomAdjustments.crop.right}% ${dicomAdjustments.crop.bottom}% ${dicomAdjustments.crop.left}%)`,
    transform: `rotate(${dicomAdjustments.rotation}deg)`,
  };

  const previewTiles = useMemo(() => {
    if (!volumePreview?.previews) {
      return [];
    }

    return [
      { id: 'axial', label: 'Axial MIP', base64: volumePreview.previews.axialMipPngBase64 },
      { id: 'coronal', label: 'Coronal MIP', base64: volumePreview.previews.coronalMipPngBase64 },
      { id: 'sagittal', label: 'Sagittal MIP', base64: volumePreview.previews.sagittalMipPngBase64 },
      { id: 'arch', label: 'Axial arch', base64: volumePreview.previews.archOverlayPngBase64 },
    ].filter((tile) => Boolean(tile.base64));
  }, [volumePreview]);

  const volumeFacts = useMemo(() => {
    const spacing = volumePreview?.volume?.spacingZyxMm ?? [];
    const huRange = volumePreview?.volume?.huRange ?? [];

    return [
      { label: 'Volume shape', value: volumePreview?.volume?.volumeShape?.join(' × ') || 'pending' },
      { label: 'Spacing', value: spacing.length === 3 ? `${spacing[0]} / ${spacing[1]} / ${spacing[2]} mm` : 'pending' },
      { label: 'HU range', value: huRange.length === 2 ? `${Math.round(huRange[0])} → ${Math.round(huRange[1])}` : 'pending' },
      { label: 'Panoramic mode', value: volumePreview?.volume?.reconstructionMode || 'baseline curved MIP' },
    ];
  }, [volumePreview]);

  const dockItems = useMemo(() => [
    { id: 'review' as const, label: 'Review', icon: Layers3, badge: `${metadata?.sliceCount ?? totalSlices}` },
    { id: 'volume' as const, label: 'Volume', icon: Box, badge: volumePreview?.volume?.volumeShape ? '3D' : 'prep' },
    { id: 'ai' as const, label: 'AI', icon: Activity, badge: 'beta' },
    { id: 'report' as const, label: 'Report', icon: FileText, badge: 'pdf' },
  ], [metadata?.sliceCount, totalSlices, volumePreview?.volume?.volumeShape]);

  const showImportHint = useCallback(() => {
    toast('Puedes subir ZIP, carpeta o un .dcm suelto; si detectamos más DICOM hermanos en la misma carpeta, cargamos la serie completa automáticamente.', 'info');
  }, [toast]);

  const studyFacts = useMemo(() => [
    { label: 'Paciente', value: metadata?.patientName || 'No identificado' },
    { label: 'Modalidad', value: metadata?.modality || 'DICOM' },
    { label: 'Serie', value: metadata?.seriesDescription || 'Serie local' },
    { label: 'Slices', value: String(metadata?.sliceCount ?? totalSlices) },
  ], [metadata, totalSlices]);

  const aiCards = useMemo(() => [
    {
      title: 'Cavity Detection',
      detail: 'Detección automática preparada para scores y overlays por pieza.',
      status: 'next',
    },
    {
      title: 'Periapical Lesion Detection',
      detail: 'Bounding boxes y prioridad clínica sobre el estudio activo.',
      status: 'planned',
    },
    {
      title: 'Real-time Analysis',
      detail: 'FastAPI + modelos CV locales con fallback a preview backend.',
      status: 'active',
    },
  ], []);
  const toolCards = useMemo(() => getTlantiCadToolsForFile(file), [file]);

  const renderViewportSurface = () => (
    <div
      className={cn(
        'relative min-h-0 overflow-hidden rounded-[28px] border pointer-events-auto shadow-xl',
        themeMode === 'dark' ? 'bg-black border-border' : 'bg-surface border-border',
      )}
    >
      <div
        className={cn(
          'absolute left-4 top-4 z-10 flex items-center gap-2 rounded-full border px-3 py-1.5 text-[11px] text-text-secondary tabular-nums',
          themeMode === 'dark' ? 'bg-surface-raised border-border-visible' : 'bg-surface border-border',
        )}
      >
        <ScanSearch size={12} className="text-[#FA93FA]" />
        dicom workspace
      </div>

      <div className="relative h-full w-full overflow-hidden">
        <div
          ref={viewportRef}
          onWheel={handleWheel}
          style={cropStyle}
          className={cn(
            'h-full w-full transition-transform duration-200',
            useFallbackPreview && 'invisible',
            themeMode === 'dark' ? 'bg-black' : 'bg-[#f6f6f8]',
          )}
        />

        {useFallbackPreview && fallbackPreview ? (
          <div className="absolute inset-0 flex items-center justify-center bg-black" style={cropStyle}>
            <img src={fallbackPreview.dataUrl} alt={file.name} className="h-full w-full object-contain" />
          </div>
        ) : null}

        {(dicomAdjustments.crop.top || dicomAdjustments.crop.right || dicomAdjustments.crop.bottom || dicomAdjustments.crop.left) ? (
          <div
            className="pointer-events-none absolute border-2 border-dashed border-[#FA93FA]/80"
            style={{
              top: `${dicomAdjustments.crop.top}%`,
              right: `${dicomAdjustments.crop.right}%`,
              bottom: `${dicomAdjustments.crop.bottom}%`,
              left: `${dicomAdjustments.crop.left}%`,
            }}
          />
        ) : null}
      </div>

      {!isReady && !useFallbackPreview && !error && <TlantiOhifLoadingIndicator themeMode={themeMode} label="Preparando render DICOM" />}
      {error && !useFallbackPreview && <TlantiOhifErrorIndicator themeMode={themeMode} details={error} />}
    </div>
  );

  return (
    <div className="absolute inset-0 z-[5] pointer-events-none">
      <TlantiOhifToolbar
        activeTool={activeTool}
        onActiveToolChange={setActiveTool}
        onResetViewport={resetViewport}
        onInvertToggle={() => setIsInverted((previous) => !previous)}
        isInverted={isInverted}
        fileName={file.name}
        metadata={metadata}
        renderMode={renderMode}
        themeMode={themeMode}
      />

      <TlantiOhifClinicalDock
        activeView={workspaceView}
        items={dockItems}
        isCollapsed={isDockCollapsed}
        isInspectorOpen={isInspectorOpen}
        onSelectView={(value: DicomWorkspaceView) => onUpdate(file.id, { dicomWorkspaceView: value })}
        onToggleCollapsed={() => setIsDockCollapsed((previous) => !previous)}
        onToggleInspector={() => setIsInspectorOpen((previous) => !previous)}
        themeMode={themeMode}
      />

      <div className="absolute right-4 top-24 z-20 pointer-events-auto sm:right-6 sm:top-[6.5rem]">
        <TlantiOhifActionMenu
          activeView={workspaceView}
          onSelectView={(value: DicomWorkspaceView) => onUpdate(file.id, { dicomWorkspaceView: value })}
          onToggleInspector={() => setIsInspectorOpen((previous) => !previous)}
          onOpenDetails={() => setIsDetailsSheetOpen(true)}
          onShowImportHint={showImportHint}
          themeMode={themeMode}
        />
      </div>

      <Sheet open={isDetailsSheetOpen} onOpenChange={setIsDetailsSheetOpen}>
        <SheetContent side="right" className="w-full max-w-xl overflow-y-auto border-border bg-surface text-text-primary sm:max-w-xl">
          <SheetHeader>
            <SheetTitle>Clinical DICOM details</SheetTitle>
            <SheetDescription>
              Metadata, previews and volume facts for the current study without covering the whole canvas.
            </SheetDescription>
          </SheetHeader>

          <div className="space-y-4 px-4 pb-6">
            <TlantiOhifStudyPanel metadata={metadata} renderMode={renderMode} themeMode={themeMode} />

            <div className="rounded-[1.35rem] border border-border bg-card p-4">
              <div className="flex items-center justify-between gap-3">
                <div>
                  <p className="text-[11px] uppercase text-text-secondary">Volume facts</p>
                  <h4 className="text-sm font-semibold text-text-display">Curved panoramic baseline</h4>
                </div>
                <Badge variant="outline" className="border-border-visible bg-surface text-text-secondary">
                  {isVolumeLoading ? 'loading' : volumePreview?.volume?.reconstructionMode || 'pending'}
                </Badge>
              </div>
              <div className="mt-4 grid gap-3 sm:grid-cols-2">
                {volumeFacts.map((fact) => (
                  <div key={fact.label} className="rounded-2xl border border-border bg-surface px-3 py-3">
                    <p className="text-[11px] text-text-secondary">{fact.label}</p>
                    <p className="mt-1 text-sm text-text-primary">{fact.value}</p>
                  </div>
                ))}
              </div>
            </div>

            {previewTiles.length ? (
              <div className="grid gap-3 sm:grid-cols-2">
                {previewTiles.map((tile) => (
                  <div key={tile.id} className="overflow-hidden rounded-[1.2rem] border border-border bg-black">
                    <div className="border-b border-border px-3 py-2 text-[11px] uppercase text-text-secondary">{tile.label}</div>
                    <img src={`data:image/png;base64,${tile.base64}`} alt={tile.label} className="h-40 w-full object-contain" />
                  </div>
                ))}
              </div>
            ) : null}
          </div>
        </SheetContent>
      </Sheet>

      <div className="absolute inset-x-4 top-24 bottom-24 pointer-events-none sm:inset-x-6 sm:top-[6.5rem] sm:bottom-6">
        <Tabs value={workspaceView} onValueChange={(value) => onUpdate(file.id, { dicomWorkspaceView: value as DicomWorkspaceView })} className="flex h-full min-h-0 flex-col gap-4">
          <div className="pointer-events-auto pl-16 sm:pl-20">
            <TabsList className="w-full justify-start overflow-x-auto">
              <TabsTrigger value="review" className="gap-2"><Layers3 size={14} />Review</TabsTrigger>
              <TabsTrigger value="volume" className="gap-2"><Box size={14} />Volume</TabsTrigger>
              <TabsTrigger value="ai" className="gap-2"><Activity size={14} />AI analysis</TabsTrigger>
              <TabsTrigger value="report" className="gap-2"><FileText size={14} />Report</TabsTrigger>
            </TabsList>
          </div>

          <TabsContent value="review" className="h-full min-h-0 flex-1">
            <div className={cn('grid h-full min-h-0 gap-4', isInspectorOpen ? 'sm:grid-cols-[minmax(0,1fr)_15rem] md:grid-cols-[minmax(0,1fr)_19rem]' : 'grid-cols-1')}>
              {renderViewportSurface()}
              {isInspectorOpen ? (
                <div className="pointer-events-auto hidden min-h-0 sm:block">
                  <TlantiOhifStudyPanel metadata={metadata} renderMode={renderMode} themeMode={themeMode} />
                </div>
              ) : null}
            </div>
          </TabsContent>

          <TabsContent value="volume" className="h-full min-h-0 flex-1">
            <div className="grid h-full min-h-0 gap-4 lg:grid-cols-[minmax(0,1fr)_20rem]">
              <div className={cn('pointer-events-auto flex min-h-0 flex-col overflow-hidden rounded-[28px] border', themeMode === 'dark' ? 'border-border bg-black' : 'border-border bg-surface')}>
                <div className="flex items-center justify-between gap-3 border-b border-border px-4 py-3">
                  <div>
                    <p className="text-[11px] uppercase text-text-secondary">Volume render</p>
                    <h3 className="text-sm font-semibold text-text-display">Vista 3D clínica y panorámica baseline</h3>
                  </div>
                  <Badge variant="outline" className="border-border-visible bg-card text-text-primary">{volumePreview?.volume?.reconstructionMode || 'MVP'}</Badge>
                </div>
                <div className="grid flex-1 min-h-0 gap-4 p-4 lg:grid-cols-[minmax(0,1fr)_18rem]">
                  <div className="grid min-h-[20rem] gap-4 lg:grid-rows-[minmax(0,1fr)_auto]">
                    <div className="relative overflow-hidden rounded-[1.5rem] border border-border bg-black">
                      {volumePreview?.previews?.panoramicPngBase64 ? (
                        <img src={`data:image/png;base64,${volumePreview.previews.panoramicPngBase64}`} alt={`${file.name} panoramic preview`} className="h-full w-full object-contain opacity-95" />
                      ) : fallbackPreview ? (
                        <img src={fallbackPreview.dataUrl} alt={file.name} className="h-full w-full object-contain opacity-90" />
                      ) : isVolumeLoading ? (
                        <div className="flex h-full items-center justify-center text-sm text-text-secondary">Preparing 3D + panoramic preview…</div>
                      ) : (
                        <div className="flex h-full items-center justify-center text-sm text-text-secondary">Volume preview pending</div>
                      )}
                      <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_35%,rgba(0,0,0,0.72)_100%)]" />
                      <div className="absolute inset-x-4 bottom-4 flex flex-wrap gap-2">
                        <Badge variant="outline" className="border-[#FA93FA]/40 bg-[#FA93FA]/10 text-[#FA93FA]">Panoramic baseline</Badge>
                        {volumePreview?.volume?.volumeShape ? <Badge variant="outline" className="border-border-visible bg-card text-text-primary">{volumePreview.volume.volumeShape.join(' × ')}</Badge> : null}
                      </div>
                    </div>

                    {previewTiles.length ? (
                      <div className="grid gap-3 md:grid-cols-2 xl:grid-cols-4">
                        {previewTiles.map((tile) => (
                          <div key={tile.id} className="overflow-hidden rounded-2xl border border-border bg-card">
                            <div className="border-b border-border px-3 py-2 text-[11px] uppercase text-text-secondary">{tile.label}</div>
                            <img src={`data:image/png;base64,${tile.base64}`} alt={tile.label} className="h-28 w-full object-contain bg-black" />
                          </div>
                        ))}
                      </div>
                    ) : null}
                  </div>

                  <div className="space-y-3">
                    <div className="rounded-2xl border border-border bg-card px-4 py-4">
                      <p className="text-[11px] uppercase text-text-secondary">Volume facts</p>
                      <div className="mt-3 space-y-2 text-sm text-text-primary">
                        {volumeFacts.map((fact) => (
                          <div key={fact.label} className="flex items-center justify-between gap-3 rounded-xl border border-border px-3 py-2"><span>{fact.label}</span><span className="tabular-nums text-text-secondary">{fact.value}</span></div>
                        ))}
                      </div>
                    </div>

                    <div className="rounded-2xl border border-border bg-card px-4 py-4">
                      <p className="text-[11px] uppercase text-text-secondary">Panoramic pipeline</p>
                      <p className="mt-2 text-sm text-text-primary text-pretty">`pydicom` carga el stack, genera un volumen HU, calcula MIP axial/coronal/sagital y estima el arco dental para una proyección panorámica curvada base lista para AI, implant planning y surgical guide.</p>
                    </div>

                    {volumeError ? (
                      <div className="rounded-2xl border border-amber-400/30 bg-amber-500/10 px-4 py-4 text-sm text-amber-200">
                        {volumeError}
                      </div>
                    ) : null}
                  </div>
                </div>
              </div>

              {isInspectorOpen ? (
                <div className="pointer-events-auto hidden min-h-0 lg:block">
                  <TlantiOhifStudyPanel metadata={metadata} renderMode={renderMode} themeMode={themeMode} />
                </div>
              ) : null}
            </div>
          </TabsContent>

          <TabsContent value="ai" className="h-full min-h-0 flex-1">
            <div className="grid h-full min-h-0 gap-4 lg:grid-cols-[minmax(0,1fr)_20rem]">
              <div className={cn('pointer-events-auto flex min-h-0 flex-col overflow-hidden rounded-[28px] border', themeMode === 'dark' ? 'border-border bg-surface-raised/95' : 'border-border bg-surface')}>
                <div className="border-b border-border px-4 py-3">
                  <p className="text-[11px] uppercase text-text-secondary">AI diagnostics</p>
                  <h3 className="text-sm font-semibold text-text-display">Análisis automático dental preparado para FastAPI</h3>
                </div>
                <div className="grid flex-1 min-h-0 gap-4 overflow-auto p-4 md:grid-cols-2 xl:grid-cols-3">
                  {aiCards.map((card) => (
                    <div key={card.title} className="rounded-2xl border border-border bg-card px-4 py-4">
                      <div className="flex items-center justify-between gap-2">
                        <p className="text-sm font-semibold text-text-display">{card.title}</p>
                        <Badge variant="outline" className="border-border-visible bg-surface text-text-secondary">{card.status}</Badge>
                      </div>
                      <p className="mt-3 text-sm text-text-secondary text-pretty">{card.detail}</p>
                    </div>
                  ))}
                </div>
              </div>

              <div className="pointer-events-auto space-y-4">
                <div className="rounded-2xl border border-border bg-card px-4 py-4">
                  <p className="text-[11px] uppercase text-text-secondary">Modelo activo</p>
                  <h4 className="mt-1 text-sm font-semibold text-text-display">FastAPI dental inference</h4>
                  <p className="mt-2 text-sm text-text-secondary text-pretty">Ruta objetivo: `pydicom` + segmentación automática + bounding boxes + export PDF/report.</p>
                </div>

                <div className="rounded-2xl border border-border bg-card px-4 py-4">
                  <p className="text-[11px] uppercase text-text-secondary">TlantiCAD Tools</p>
                  <div className="mt-3 space-y-2">
                    {toolCards.map((tool) => (
                      <div key={tool.id} className="rounded-xl border border-border px-3 py-3">
                        <div className="flex items-center justify-between gap-2">
                          <p className="text-sm font-medium text-text-primary">{tool.label}</p>
                          <Badge variant="outline" className="border-border-visible bg-surface text-text-secondary">{tool.badge}</Badge>
                        </div>
                        <p className="mt-1 text-sm text-text-secondary text-pretty">{tool.summary}</p>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="rounded-2xl border border-border bg-card px-4 py-4">
                  <p className="text-[11px] uppercase text-text-secondary">Exportables</p>
                  <div className="mt-3 flex flex-wrap gap-2">
                    <Button type="button" variant="outline" size="sm"><Download size={14} /> PNG overlay</Button>
                    <Button type="button" variant="outline" size="sm"><FileText size={14} /> PDF report</Button>
                  </div>
                </div>
              </div>
            </div>
          </TabsContent>

          <TabsContent value="report" className="h-full min-h-0 flex-1">
            <div className="grid h-full min-h-0 gap-4 lg:grid-cols-[minmax(0,1fr)_20rem]">
              <div className={cn('pointer-events-auto flex min-h-0 flex-col overflow-hidden rounded-[28px] border', themeMode === 'dark' ? 'border-border bg-surface-raised/95' : 'border-border bg-surface')}>
                <div className="border-b border-border px-4 py-3">
                  <p className="text-[11px] uppercase text-text-secondary">Clinical report</p>
                  <h3 className="text-sm font-semibold text-text-display">Resumen listo para exportación</h3>
                </div>
                <div className="grid flex-1 min-h-0 gap-4 overflow-auto p-4 lg:grid-cols-[minmax(0,1fr)_18rem]">
                  <div className="space-y-4">
                    <div className="rounded-2xl border border-border bg-card px-4 py-4">
                      <p className="text-[11px] uppercase text-text-secondary">Hallazgos del estudio</p>
                      <div className="mt-3 grid gap-3 sm:grid-cols-2">
                        {studyFacts.map((fact) => (
                          <div key={fact.label} className="rounded-xl border border-border px-3 py-3">
                            <p className="text-[11px] text-text-secondary">{fact.label}</p>
                            <p className="mt-1 text-sm font-medium text-text-primary tabular-nums">{fact.value}</p>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="rounded-2xl border border-border bg-card px-4 py-4">
                      <p className="text-[11px] uppercase text-text-secondary">Resultado esperado</p>
                      <p className="mt-2 text-sm text-text-secondary text-pretty">Esta vista consolida metadata DICOM, overlays IA, capturas del viewer y exportes clínicos. La generación automática del PDF queda lista para el siguiente sprint.</p>
                    </div>
                  </div>

                  <div className="space-y-4">
                    <div className="rounded-2xl border border-border bg-card px-4 py-4">
                      <p className="text-[11px] uppercase text-text-secondary">Checklist</p>
                      <div className="mt-3 space-y-2 text-sm text-text-primary">
                        <div className="flex items-center justify-between rounded-xl border border-border px-3 py-2"><span>Metadata</span><Sparkles size={14} className="text-emerald-300" /></div>
                        <div className="flex items-center justify-between rounded-xl border border-border px-3 py-2"><span>Preview backend</span><Sparkles size={14} className="text-emerald-300" /></div>
                        <div className="flex items-center justify-between rounded-xl border border-border px-3 py-2"><span>Reporte PDF</span><Move3d size={14} className="text-text-secondary" /></div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {isInspectorOpen ? (
                <div className="pointer-events-auto hidden min-h-0 lg:block">
                  <TlantiOhifStudyPanel metadata={metadata} renderMode={renderMode} themeMode={themeMode} />
                </div>
              ) : null}
            </div>
          </TabsContent>
        </Tabs>
      </div>
    </div>
  );
}
